const dronedomeList = [];
let num = 0;
for (let index = 1; index < 8; index++) {
    num = index % 2;
    dronedomeList.push({
        idx: index,
        name: `드론돔_${index}`,
        detectCriteria: num === 0 ? 1 : 2,
        point: num !== 0 ? ['278.333', '178.444'] : [], // detectCriteria 이 좌표값 중심일 경우만 값이 있음
        detectArea: num === 0 ? 1 : 2,
        scanningSpeed: num === 0 ? 0.08 : -1,
    });
}

export default dronedomeList;
