<template>
    <div class="popup_wrap">
        <div class="popup_content">
            <p class="popup_title">{{ selectInfo.name }} 설정</p>
            <dl>
                <dt>탐지 기준 :</dt>
                <dd>
                    <v-radio-group hide-details v-model="model.DETECT_TYPE" row @change="criteriaChange()">
                        <v-radio v-for="n in ['D','C']" :key="n" :label="n === 'D' ? '드론돔을 중심으로' : '좌표값을 중심으로'" :value="n"></v-radio>
                    </v-radio-group>
                </dd>
            </dl>
            <dl>
                <dt :class="model.DETECT_TYPE === 'D' ? 'disable' : ''">위도 :</dt>
                <dd>
                    <input type="text" v-model="model.LATITUDE" :disabled="model.DETECT_TYPE === 'D'" />
                </dd>
                <dt :class="model.DETECT_TYPE === 'D' ? 'disable' : ''">경도 :</dt>
                <dd>
                    <input type="text" v-model="model.LONGITUDE" :disabled="model.DETECT_TYPE === 'D'" />
                </dd>
            </dl>
            <dl>
                <dt>탐지 영역 :</dt>
                <dd>
                    <v-radio-group hide-details v-model="model.DETECT_RANGE" row>
                        <v-radio
                            v-for="n in ['C','P']"
                            :key="n"
                            :label="n === 'C' ? '원' : '해당 좌표에만'"
                            :value="n"
                            :disabled="n === 'P' && model.DETECT_RANGE === 'P'"
                        ></v-radio>
                    </v-radio-group>
                </dd>
            </dl>
            <dl>
                <dt :class="model.DETECT_RANGE !== 'C' ? 'disable' : ''">스캐닝 속도 :</dt>
                <dd>
                    <input type="number" max="0.1" min="0.00" step="0.01" v-model="model.SCANNING_SPEED" :disabled="model.DETECT_RANGE !== 'C'" />

                    <span class="txt_max_speed" :class="model.DETECT_RANGE !== 'C' ? 'disable' : ''">최대 속도 0.1</span>
                </dd>
            </dl>
            <div class="btn_area">
                <v-btn elevation="3" color="primary" @click="doSave"> 확인 </v-btn>
                <v-btn outlined plain elevation="3" @click="popupCloseNo">취소</v-btn>
            </div>
        </div>
        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>
<script>
import * as LogUtil from "@/common/LogUtil";

import * as DeviceConfigDronedom from "@/rest/DeviceConfigDronedom";
import AlertModal from '@/components/modal/AlertModal'

export default {
  components: {
    AlertModal
  },
  data: () => ({
    alertModalParams: { isOpened: false, title: '', message: ''},
    model: {},
  }),
  props: ['selectInfo'],
  mounted() {
    // this.criteriaGroup = this.selectInfo.detectCriteria;
    // this.areaGroup = this.selectInfo.detectArea;
    // this.scanningSpeed = this.selectInfo.scanningSpeed < 0 ? '' : this.selectInfo.scanningSpeed;
    this.model = this.selectInfo;
    // console.log('this.criteriaGroup', this.criteriaGroup);
  },
  methods: {
    showAlertModal(msg) {
      this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
    },
    popupCloseNo() {
      this.$emit('popupCloseNo', false);
      LogUtil.debug('DronedomSetting: popupCloseNo()');
    },
    criteriaChange() {
      if (this.criteriaGroup === 1) {
        this.areaGroup = 1;
      }
    },
    doSave() {
      LogUtil.debug('DronedomSetting: doSave(): this.model=', this.model);
      let model = {
        DEVICE_CONFIG_DRONEDOM_ID: this.model.DEVICE_CONFIG_DRONEDOM_ID != null ? this.model.DEVICE_CONFIG_DRONEDOM_ID : -1,
        DEVICE_ID: this.model.DEVICE_ID,
        DETECT_TYPE: this.model.DETECT_TYPE,
        LATITUDE: this.model.LATITUDE,
        LONGITUDE: this.model.LONGITUDE,
        DETECT_RANGE: this.model.DETECT_RANGE,
        SCANNING_SPEED: this.model.SCANNING_SPEED,
      }
      LogUtil.debug('DronedomSetting: doSave(): model=', model);
      DeviceConfigDronedom.save(model).then(res => {
        if(res.data.RES_CODE>=0) {
          LogUtil.debug('DronedomSetting: doSave(): res.data.RES_CODE=', res.data);
          if(this.model.DEVICE_CONFIG_SCANNER_ID === -1) {
            this.model.DEVICE_CONFIG_SCANNER_ID = res.data.insertId;
            LogUtil.debug('DronedomSetting: doSave(): this.model=', this.model);
          } else {
            LogUtil.debug('DronedomSetting: doSave(): this.model.DEVICE_CONFIG_SCANNER_ID=', this.model.DEVICE_CONFIG_SCANNER_ID);
          }
          this.$emit('popupCloseYes', false);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
    },
  },
};
</script>

<style lang="scss" scoped>
.popup_wrap {
    .popup_content {
        width: 600px;
        padding: 0 10px;
        .popup_title {
            @include centerAlign();
            height: 52px;
            margin-bottom: 27px;
            border-bottom: 1px solid #ccc;
            font: {
                size: 20px;
                weight: 600;
            }
        }
        .disable {
            color: #ccc !important;
        }
        dl {
            @include hCenterAlign();
            & + dl {
                margin-top: 20px;
            }
            dt {
                width: 170px;
                padding-right: 14px;
                text-align: right;
                font: {
                    size: 15px;
                    weight: 700;
                }
            }
            dd {
                input[type='text'],
                input[type='number'] {
                    width: 100px;
                    height: 38px;
                    border: 1px solid #ccc;
                    border-radius: 8px;
                    text-align: center;
                }
                & + dt {
                    width: 80px;
                }
                .v-input--selection-controls {
                    margin-top: 0 !important;
                    padding-top: 0 !important;
                }
                .txt_max_speed {
                    display: inline-block;
                    padding-left: 15px;
                    font: {
                        size: 15px;
                    }
                    color: #ae0003;
                }
            }
        }
        .btn_area {
            @include centerAlign();
            width: 100%;
            margin-top: 45px;
            border-top: 1px solid #ccc;
            button + button {
                margin-left: 14px;
            }
        }
    }
}
</style>
